import React, { useEffect } from 'react';
import styled from 'styled-components';
import AOS from 'aos';
import 'aos/dist/aos.css';
import Footer from '../components/Footer';

const EventsPage = styled.div`
  min-height: 100vh;
  background: #000;
  padding-top: 80px;
`;

const EventsSection = styled.section`
  padding: 100px 10%;
`;

const Header = styled.div`
  text-align: center;
  margin-bottom: 60px;

  h2 {
    font-size: 3rem;
    color: #00FFFF;
    margin-bottom: 20px;
    position: relative;
    display: inline-block;

    &::after {
      content: '';
      position: absolute;
      bottom: -10px;
      left: 50%;
      transform: translateX(-50%);
      width: 80px;
      height: 4px;
      background: linear-gradient(to right, #00FFFF, #00BFFF);
      border-radius: 2px;
    }
  }
`;

const EventGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 30px;
`;

const EventCard = styled.div`
  background: rgba(255, 255, 255, 0.05);
  border-radius: 15px;
  overflow: hidden;
  border: 1px solid rgba(255, 255, 255, 0.1);
  transition: transform 0.3s ease;

  &:hover {
    transform: translateY(-10px);
  }

  img {
    width: 100%;
    height: 200px;
    object-fit: cover;
  }

  .content {
    padding: 20px;

    h3 {
      color: #00FFFF;
      margin-bottom: 10px;
      font-size: 1.5rem;
    }

    p {
      color: rgba(255, 255, 255, 0.8);
      margin-bottom: 20px;
    }

    .date {
      color: #00FFFF;
      font-weight: bold;
    }

    .status {
      display: inline-block;
      padding: 5px 15px;
      border-radius: 15px;
      font-size: 0.9rem;
      margin-top: 10px;

      &.upcoming {
        background-color: rgb(102, 255, 85);
        color: black;
      }

      &.past {
        background-color: rgba(255, 255, 255, 0.2);
        color: white;
      }
    }
  }
`;

const Events = () => {
  const events = [
    {
      title: "OPTIMUS ARENA 2025",
      description: "Our annual flagship hackathon event. Join us for 48 hours of coding, innovation, and fun!",
      image: require("../assets/event1.jpeg"),
      date: "May 29, 2025",
      status: "upcoming"
    }
    // Add more events here
  ];

  return (
    <EventsPage>
      <EventsSection>
        <Header>
          <h2 data-aos="fade-up">Our Events</h2>
        </Header>
        <EventGrid>
          {events.map((event, index) => (
            <EventCard key={index} data-aos="fade-up" data-aos-delay={100 * (index + 1)}>
              <img src={event.image} alt={event.title} />
              <div className="content">
                <h3>{event.title}</h3>
                <p>{event.description}</p>
                <div className="date">{event.date}</div>
                <span className={`status ${event.status}`}>
                  {event.status.charAt(0).toUpperCase() + event.status.slice(1)}
                </span>
              </div>
            </EventCard>
          ))}
        </EventGrid>
      </EventsSection>
      <Footer />
    </EventsPage>
  );
};

export default Events;
